pub fn generated_intrinsic_target_by_marker(
    marker: &str,
) -> Option<&'static GeneratedIntrinsicTarget> {
    GENERATED_INTRINSIC_TARGETS
        .iter()
        .find(|target| target.marker == marker)
}

pub fn generated_intrinsic_targets_by_op_name(
    op_name: &str,
) -> impl Iterator<Item = &'static GeneratedIntrinsicTarget> + '_ {
    GENERATED_INTRINSIC_TARGETS
        .iter()
        .filter(move |target| target.dialect_op == op_name)
}

pub fn generated_intrinsic_target_by_op_name(
    op_name: &str,
) -> Option<&'static GeneratedIntrinsicTarget> {
    generated_intrinsic_targets_by_op_name(op_name).next()
}

pub fn generated_intrinsic_target(op_name: &str) -> Option<&'static GeneratedIntrinsicTarget> {
    generated_intrinsic_target_by_op_name(op_name)
}

pub fn generated_intrinsic_operation_matches(
    ctx: &Context,
    target: &GeneratedIntrinsicTarget,
    operation: Ptr<Operation>,
) -> bool {
    match target.variant {
        GeneratedIntrinsicVariant::Scalar => true,
        GeneratedIntrinsicVariant::Ldmatrix {
            shape,
            multiplicity,
            layout,
        } => {
            let Some(op) = Operation::get_op::<LdmatrixOp>(operation, ctx) else {
                return false;
            };
            let shape_matches = matches!(shape, GeneratedLdmatrixShape::M8n8)
                && op.get_attr_nvvm_ldmatrix_shape(ctx).as_deref()
                    == Some(&LdmatrixShapeAttr::M8n8);
            let multiplicity_matches = match multiplicity {
                GeneratedLdmatrixMultiplicity::X1 => {
                    op.get_attr_nvvm_ldmatrix_multiplicity(ctx).as_deref()
                        == Some(&LdmatrixMultiplicityAttr::X1)
                }
                GeneratedLdmatrixMultiplicity::X2 => {
                    op.get_attr_nvvm_ldmatrix_multiplicity(ctx).as_deref()
                        == Some(&LdmatrixMultiplicityAttr::X2)
                }
                GeneratedLdmatrixMultiplicity::X4 => {
                    op.get_attr_nvvm_ldmatrix_multiplicity(ctx).as_deref()
                        == Some(&LdmatrixMultiplicityAttr::X4)
                }
            };
            let layout_matches = match layout {
                GeneratedLdmatrixLayout::Normal => {
                    op.get_attr_nvvm_ldmatrix_layout(ctx).as_deref()
                        == Some(&LdmatrixLayoutAttr::Normal)
                }
                GeneratedLdmatrixLayout::Transposed => {
                    op.get_attr_nvvm_ldmatrix_layout(ctx).as_deref()
                        == Some(&LdmatrixLayoutAttr::Transposed)
                }
            };
            shape_matches
                && multiplicity_matches
                && layout_matches
                && op.get_attr_nvvm_ldmatrix_element(ctx).as_deref()
                    == Some(&LdmatrixElementAttr::B16)
                && op.get_attr_nvvm_ldmatrix_state_space(ctx).as_deref()
                    == Some(&LdmatrixStateSpaceAttr::Shared)
        }
        GeneratedIntrinsicVariant::PackedAtomic { format } => {
            let Some(op) = Operation::get_op::<PackedAtomicAddOp>(operation, ctx) else {
                return false;
            };
            let format_matches = match format {
                GeneratedPackedAtomicFormat::F16x2 => {
                    op.get_attr_nvvm_packed_atomic_format(ctx).as_deref()
                        == Some(&PackedAtomicFormatAttr::F16x2)
                }
                GeneratedPackedAtomicFormat::Bf16x2 => {
                    op.get_attr_nvvm_packed_atomic_format(ctx).as_deref()
                        == Some(&PackedAtomicFormatAttr::Bf16x2)
                }
            };
            format_matches
                && op.get_attr_nvvm_packed_atomic_state_space(ctx).as_deref()
                    == Some(&PackedAtomicStateSpaceAttr::Global)
                && op.get_attr_nvvm_packed_atomic_ordering(ctx).as_deref()
                    == Some(&PackedAtomicOrderingAttr::Relaxed)
                && op.get_attr_nvvm_packed_atomic_scope(ctx).as_deref()
                    == Some(&PackedAtomicScopeAttr::Gpu)
                && op.get_attr_nvvm_packed_atomic_rounding(ctx).as_deref()
                    == Some(&PackedAtomicRoundingAttr::Rn)
                && op.get_attr_nvvm_packed_atomic_subnormal(ctx).as_deref()
                    == Some(&PackedAtomicSubnormalAttr::NoFtz)
                && op.get_attr_nvvm_packed_atomic_atomicity(ctx).as_deref()
                    == Some(&PackedAtomicAtomicityAttr::PerElement)
        }
    }
}

